using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

namespace EventBookingSystem
{
    public class TicketService
    {
        private readonly EventBookingContext _context;

        public TicketService(EventBookingContext context)
        {
            _context = context;
        }

        public async Task<bool> HandleConcurrentTicketPurchaseAsync(int eventId, int quantity)
        {
            // Check available seats
            var availableSeats = await _context.Events.Find(eventId).AvailableSeats;
            if (availableSeats < quantity)
                return false;

            // Validate purchase quantity
            if (quantity <= 0)
                return false;

            // Update inventory
            var updatedInventory = _context.Events.Find(eventId).AvailableSeats - quantity;
            await _context.SaveChangesAsync();

            return true;
        }
    }
}